// 1. Sadə Class və Constructor
class Robot {
  constructor(name, power) {
    this.name = name;
    this.power = power;
  }

  move() {
    return `${this.name} hərəkət edir! Güc: ${this.power}`;
  }
}

// Yeni robotlar yaratma
const robot1 = new Robot("R1", 100);
const robot2 = new Robot("R2", 150);

console.log(robot1.name); // "R1"
console.log(robot2.power); // 150
console.log(robot1.move()); // "R1 hərəkət edir! Güc: 100"

// 2. Metodlar və xüsusiyyətlər
class AdvancedRobot {
  constructor(name, power, type) {
    this.name = name;
    this.power = power;
    this.type = type;
    this.status = "off";
  }

  turnOn() {
    this.status = "on";
    return `${this.name} aktivləşdi!`;
  }

  upgradePower(newPower) {
    this.power += newPower;
    return `${this.name} gücü ${this.power}-ə yüksəldi!`;
  }
}

const advancedBot = new AdvancedRobot("AR1", 200, "Security");
console.log(advancedBot.turnOn()); // "AR1 aktivləşdi!"
console.log(advancedBot.upgradePower(50)); // "AR1 gücü 250-ə yüksəldi!"
console.log(advancedBot.status); // "on"

// 3. Varsayılan dəyərlər
class CustomRobot {
  constructor(name, power = 100) {
    this.name = name;
    this.power = power;
  }

  report() {
    return `Robot: ${this.name}, Güc: ${this.power}`;
  }
}

const defaultBot = new CustomRobot("DR1");
console.log(defaultBot.report()); // "Robot: DR1, Güc: 100"

// 4. Dinamik xüsusiyyətlər
const dynamicBot = new Robot("DynamicBot", 300);
dynamicBot.color = "blue"; // Yeni xüsusiyyət əlavə etmək
console.log(dynamicBot.color); // "blue"

// Təhlükə nümunəsi: Səhv constructor
class FaultyRobot {
  constructor(name) {
    this.name = name;
    this.power = undefined; // Səhv: güc təyin edilməyib
  }

  move() {
    return `${this.name} hərəkət edir! Güc: ${this.power}`;
  }
}

const faultyBot = new FaultyRobot("FR1");
console.log(faultyBot.move()); // "FR1 hərəkət edir! Güc: undefined"

// Düzgün yanaşma
class SafeRobot {
  constructor(name, power = 100) {
    this.name = name;
    this.power = power;
  }

  move() {
    if (this.power === undefined) {
      return "Güc təyin edilməyib!";
    }
    return `${this.name} hərəkət edir! Güc: ${this.power}`;
  }
}

const safeBot = new SafeRobot("SR1");
console.log(safeBot.move()); // "SR1 hərəkət edir! Güc: 100"

// Dinamik metod əlavə etmə
const customBot = new SafeRobot("CR1", 200);
customBot.speak = function() {
  return `${this.name} danışır!`;
};
console.log(customBot.speak()); // "CR1 danışır!"

