// 1. Simple Class and Constructor
class Robot {
  constructor(name, power) {
    this.name = name;
    this.power = power;
  }

  move() {
    return `${this.name} is moving! Power: ${this.power}`;
  }
}

// Creating new robots
const robot1 = new Robot("R1", 100);
const robot2 = new Robot("R2", 150);

console.log(robot1.name); // "R1"
console.log(robot2.power); // 150
