// 2. Methods and properties
class AdvancedRobot {
  constructor(name, power, type) {
    this.name = name;
    this.power = power;
    this.type = type;
    this.status = "off";
  }

  turnOn() {
    this.status = "on";
    return `${this.name} activated!`;
  }

  upgradePower(newPower) {
    this.power += newPower;
    return `${this.name} power upgraded to ${this.power}!`;
  }
}

const advancedBot = new AdvancedRobot("AR1", 200, "Security");
console.log(advancedBot.turnOn()); // "AR1 activated!"
console.log(advancedBot.upgradePower(50)); // "AR1 power upgraded to 250!"
console.log(advancedBot.status); // "on"

// 3. Default values
class CustomRobot {
  constructor(name, power = 100) {
    this.name = name;
    this.power = power;
  }

  report() {
    return `Robot: ${this.name}, Power: ${this.power}`;
  }
}

const defaultBot = new CustomRobot("DR1");
console.log(defaultBot.report()); // "Robot: DR1, Power: 100"

// 4. Dynamic properties
const dynamicBot = new Robot("DynamicBot", 300);
dynamicBot.color = "blue"; // Adding a new property
console.log(dynamicBot.color); // "blue"

// Danger example: Faulty constructor
class FaultyRobot {
  constructor(name) {
    this.name = name;
    this.power = undefined; // Error: power not set
  }

  move() {
    return `${this.name} is moving! Power: ${this.power}`;
  }
}

const faultyBot = new FaultyRobot("FR1");
console.log(faultyBot.move()); // "FR1 is moving! Power: undefined"

// Safe approach
class SafeRobot {
  constructor(name, power = 100) {
    this.name = name;
    this.power = power;
  }

  move() {
    if (this.power === undefined) {
      return "Power not set!";
    }
    return `${this.name} is moving! Power: ${this.power}`;
  }
}

const safeBot = new SafeRobot("SR1");
console.log(safeBot.move()); // "SR1 is moving! Power: 100"

// Dynamic method addition
const customBot = new SafeRobot("CR1", 200);
customBot.speak = function() {
  return `${this.name} is speaking!`;
};
console.log(customBot.speak()); // "CR1 is speaking!"

